function handleAuthorizationCodeGrant(req, res, params) {
  const { code, redirect_uri, client_id, client_secret, code_verifier } = params;

  // Validate required parameters
  if (!code || !redirect_uri || !client_id) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Missing required parameters: code, redirect_uri, client_id'
    });
  }

  // Authenticate client
  const client = clients.get(client_id);
  if (!client) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication failed'
    });
  }

  // Verify client secret (if provided / confidential client)
  if (client_secret) {
    if (!secureCompare(client_secret, client.client_secret)) {
      return res.status(401).json({
        error: 'invalid_client',
        error_description: 'Client authentication failed'
      });
    }
  }

  // Look up authorization code
  const authCode = authorizationCodes.get(code);
  if (!authCode) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code is invalid or expired'
    });
  }

  // Check if code has already been used (replay protection)
  if (authCode.used) {
    // If a code is reused, revoke all tokens issued with this code (security measure per RFC 6749 Section 4.1.2)
    authorizationCodes.delete(code);
    // Revoke associated tokens
    for (const [token, data] of accessTokens) {
      if (data.userId === authCode.userId && data.clientId === authCode.clientId) {
        accessTokens.delete(token);
      }
    }
    for (const [token, data] of refreshTokens) {
      if (data.userId === authCode.userId && data.clientId === authCode.clientId) {
        refreshTokens.delete(token);
      }
    }
    console.warn(`[SECURITY] Authorization code reuse detected for client ${client_id}, user ${authCode.userId}. All associated tokens revoked.`);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code has already been used. All associated tokens have been revoked.'
    });
  }

  // Check expiry
  if (authCode.expiresAt < Date.now()) {
    authorizationCodes.delete(code);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code has expired'
    });
  }

  // Verify client_id matches
  if (!secureCompare(authCode.clientId, client_id)) {
    authorizationCodes.delete(code);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code was not issued to this client'
    });
  }

  // Verify redirect_uri matches exactly
  if (!secureCompare(authCode.redirectUri, redirect_uri)) {
    authorizationCodes.delete(code);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'redirect_uri does not match the one used in the authorization request'
    });
  }

  // PKCE verification
  if (authCode.codeChallenge) {
    if (!code_verifier) {
      return res.status(400).json({
        error: 'invalid_grant',
        error_description: 'code_verifier is required for PKCE'
      });
    }
    const method = authCode.codeChallengeMethod || 'plain';
    if (!verifyCodeChallenge(code_verifier, authCode.codeChallenge, method)) {
      authorizationCodes.delete(code);
      return res.status(400).json({
        error: 'invalid_grant',
        error_description: 'PKCE code_verifier verification failed'
      });
    }
  } else if (!client_secret) {
    // If no PKCE and no client_secret, reject (public clients must use PKCE)
    authorizationCodes.delete(code);
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Public clients must use PKCE'
    });
  }

  // Mark code as used (instead of deleting, to detect replay)
  authCode.used = true;

  // Generate tokens
  const accessToken = generateSecureToken(32);
  const refreshTokenValue = generateSecureToken(48);

  const accessTokenExpiresIn = 3600; // 1 hour

  accessTokens.set(accessToken, {
    clientId: client_id,
    userId: authCode.userId,
    scope: authCode.scope,
    expiresAt: Date.now() + accessTokenExpiresIn * 1000
  });

  refreshTokens.set(refreshTokenValue, {
    clientId: client_id,
    userId: authCode.userId,
    scope: authCode.scope
  });

  // Set cache control headers
  res.set('Cache-Control', 'no-store');
  res.set('Pragma', 'no-cache');

  return res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: accessTokenExpiresIn,
    refresh_token: refreshTokenValue,
    scope: authCode.scope
  });
}

function handleRefreshTokenGrant(req, res, params) {
  const { refresh_token, client_id, client_secret } = params;

  if (!refresh_token || !client_id) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Missing required parameters'
    });
  }

  // Authenticate client
  const client = clients.get(client_id);
  if (!client) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication failed'
    });
  }

  if (client_secret && !secureCompare(client_secret, client.client_secret)) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication failed'
    });
  }

  // Look up refresh token
  const storedRefreshToken = refreshTokens.get(refresh_token);
  if (!storedRefreshToken) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Refresh token is invalid'
    });
  }

  // Verify client
  if (!secureCompare(storedRefreshToken.clientId, client_id)) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Refresh token was not issued to this client'
    });
  }

  // Rotate refresh token (invalidate old, issue new)
  refreshTokens.delete(refresh_token);

  const newAccessToken = generateSecureToken(32);
  const newRefreshToken = generateSecureToken(48);
  const accessTokenExpiresIn = 3600;

  accessTokens.set(newAccessToken, {
    clientId: client_id,
    userId: storedRefreshToken.userId,
    scope: storedRefreshToken.scope,
    expiresAt: Date.now() + accessTokenExpiresIn * 1000
  });

  refreshTokens.set(newRefreshToken, {
    clientId: client_id,
    userId: storedRefreshToken.userId,
    scope: storedRefreshToken.scope
  });

  res.set('Cache-Control', 'no-store');
  res.set('Pragma', 'no-cache');

  return res.json({
    access_token: newAccessToken,
    token_type: 'Bearer',
    expires_in: accessTokenExpiresIn,
    refresh_token: newRefreshToken,
    scope: storedRefreshToken.scope
  });
}

// POST /revoke - Token revocation endpoint (RFC 7009)
app.post('/revoke', (req, res) => {
  const { token, token_type_hint } = req.body;

  if (!token) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Missing token parameter'
    });
  }

  // Try to revoke as access token
  if (token_type_hint === 'access_token' || !token_type_hint) {
    if (accessTokens.has(token)) {
      accessTokens.delete(token);
      return res.status(200).send();
    }
  }

  // Try to revoke as refresh token
  if (token_type_hint === 'refresh_token' || !token_type_hint) {
    if (refreshTokens.has(token)) {
      refreshTokens.delete(token);
      return res.status(200).send();
    }
  }

  // If not found with hint, try the other type
  if (accessTokens.has(token)) {
    accessTokens.delete(token);
  } else if (refreshTokens.has(token)) {
    refreshTokens.delete(token);
  }

  // Always return 200 per RFC 7009
  return res.status(200).send();
});

// GET /userinfo - Protected resource endpoint (for testing)
app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    res.set('WWW-Authenticate', 'Bearer');
    return res.status(401).json({
      error: 'invalid_token',
      error_description: 'Missing or invalid access token'
    });
  }

  const token = authHeader.slice(7);
  const tokenData = accessTokens.get(token);

  if (!tokenData) {
    res.set('WWW-Authenticate', 'Bearer error="invalid_token"');
    return res.status(401).json({
      error: 'invalid_token',
      error_description: 'Access token is invalid or expired'
    });
  }

  if (tokenData.expiresAt < Date.now()) {
    accessTokens.delete(token);
    res.set('WWW-Authenticate', 'Bearer error="invalid_token"');
    return res.status(401).json({
      error: 'invalid_token',
      error_description: 'Access token has expired'
    });
  }

  const user = users.get(tokenData.userId);
  if (!user) {
    return res.status(500).json({
      error: 'server_error',
      error_description: 'User not found'
    });
  }

  const userInfo = { sub: user.username };
  const scopes = tokenData.scope.split(' ');

  if (scopes.includes('profile')) {
    userInfo.name = user.name;
  }
  if (scopes.includes('email')) {
    userInfo.email = `${user.username}@example.com`;
  }

  return res.json(userInfo);
});

